@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

/* ─── Design Tokens ──────────────────────────────────────────── */
:root {
  --primary:        #2563eb;
  --primary-dark:   #1d4ed8;
  --primary-light:  #eff6ff;
  --sidebar-bg:     #0f172a;
  --sidebar-hover:  #1e293b;
  --sidebar-active: #2563eb;
  --surface:        #ffffff;
  --surface-2:      #f8fafc;
  --border:         #e2e8f0;
  --text:           #1e293b;
  --text-muted:     #64748b;
  --danger:         #ef4444;
  --danger-light:   #fef2f2;
  --success:        #22c55e;
  --success-light:  #f0fdf4;
  --warning:        #f59e0b;
  --warning-light:  #fffbeb;
  --info:           #06b6d4;
  --info-light:     #ecfeff;
  --sidebar-width:  240px;
  --topbar-height:  60px;
  --radius:         10px;
  --radius-sm:      6px;
  --shadow:         0 1px 3px rgba(0,0,0,.08), 0 1px 2px rgba(0,0,0,.06);
  --shadow-md:      0 4px 12px rgba(0,0,0,.1);
}

/* ─── Reset / Base ───────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { font-size: 14px; }
body {
  font-family: 'Inter', sans-serif;
  background: var(--surface-2);
  color: var(--text);
  line-height: 1.5;
}
a { text-decoration: none; color: inherit; }
img { max-width: 100%; }
ul { list-style: none; }

/* ─── Layout ─────────────────────────────────────────────────── */
.dd-wrapper {
  display: flex;
  min-height: 100vh;
}

/* ─── Sidebar ────────────────────────────────────────────────── */
.dd-sidebar {
  width: var(--sidebar-width);
  background: var(--sidebar-bg);
  display: flex;
  flex-direction: column;
  position: fixed;
  top: 0; left: 0;
  height: 100vh;
  z-index: 100;
  transition: transform .25s ease, width .25s ease;
  overflow: hidden;
}
.dd-sidebar.collapsed { width: 64px; }
.dd-sidebar.mobile-hidden { transform: translateX(-100%); }

.dd-sidebar-brand {
  height: var(--topbar-height);
  display: flex;
  align-items: center;
  padding: 0 16px;
  border-bottom: 1px solid rgba(255,255,255,.06);
  flex-shrink: 0;
}
.dd-sidebar-brand img { height: 32px; }
.dd-sidebar-brand .brand-text {
  color: #fff;
  font-size: 1.1rem;
  font-weight: 700;
  margin-left: 10px;
  white-space: nowrap;
  opacity: 1;
  transition: opacity .2s;
}
.dd-sidebar.collapsed .brand-text { opacity: 0; }

.dd-sidebar-nav {
  padding: 12px 8px;
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}
.dd-nav-section {
  font-size: .65rem;
  font-weight: 600;
  letter-spacing: .08em;
  text-transform: uppercase;
  color: #475569;
  padding: 12px 8px 4px;
  white-space: nowrap;
}
.dd-sidebar.collapsed .dd-nav-section { opacity: 0; }

.dd-nav-link {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 9px 10px;
  border-radius: var(--radius-sm);
  color: #94a3b8;
  font-size: .875rem;
  font-weight: 500;
