@app.route("/")
@app.route("/login", methods=["GET"])
def login_get():
    return render_template("login.html")


@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login_get"))


@app.route("/register", methods=["GET"])
def register_get():
