                </td>
            `;
            tr.querySelector('.edit').addEventListener('click', () => openEdit(v.id));
            tr.querySelector('.delete').addEventListener('click', () => deleteVehicle(v.id, v.plate));
            tbody.appendChild(tr);
        });
    }

    function openAdd() {
        editingId = null;
        document.getElementById('vehicleModalTitle').textContent = 'Add Vehicle';
        clearForm();
        populateCustomerSelect(customerSel, '');
        modal.show();
    }

    function openEdit(id) {
        fetch(`/api/vehicles/${id}`)
            .then(r => r.json())
            .then(v => {
                editingId = id;
                document.getElementById('vehicleModalTitle').textContent = 'Edit Vehicle';
                populateCustomerSelect(customerSel, v.customer_id);
                document.getElementById('vehiclePlate').value = v.plate;
                document.getElementById('vehicleYear').value  = v.year || '';
                document.getElementById('vehicleMake').value  = v.make;
                document.getElementById('vehicleModel').value = v.model;
                document.getElementById('vehicleColor').value = v.color || '';
                modal.show();
            });
    }

    function save() {
        const customer_id = document.getElementById('vehicleCustomerId').value;
        const plate       = document.getElementById('vehiclePlate').value.trim().toUpperCase();
        const year        = parseInt(document.getElementById('vehicleYear').value) || null;
        const make        = document.getElementById('vehicleMake').value.trim();
        const model       = document.getElementById('vehicleModel').value.trim();
        const color       = document.getElementById('vehicleColor').value.trim();

        if (!customer_id) { alert('Please select a customer.'); return; }
        if (!plate || !make || !model) { alert('Plate, make, and model are required.'); return; }

        const payload = { customer_id: parseInt(customer_id), plate, year, make, model, color };
        const url     = editingId ? `/api/vehicles/${editingId}` : '/api/vehicles';
        const method  = editingId ? 'PUT' : 'POST';

        fetch(url, {
            method,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        })
        .then(r => { if (!r.ok) return r.json().then(e => { throw new Error(e.error); }); return r.json(); })
        .then(() => { modal.hide(); load(); })
        .catch(err => alert(err.message));
    }

    function deleteVehicle(id, plate) {
        if (!confirm(`Delete vehicle "${plate}"? This will also remove its job orders.`)) return;
        fetch(`/api/vehicles/${id}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(() => load())
            .catch(err => alert(err.message));
    }

    function clearForm() {
        ['vehiclePlate', 'vehicleYear', 'vehicleMake', 'vehicleModel', 'vehicleColor'].forEach(id => {
            document.getElementById(id).value = '';
        });
    }

    function showError(msg) {
        tbody.innerHTML = `<tr><td colspan="6" class="dd-table-empty" style="color:var(--danger);">
            <i class="fas fa-circle-exclamation"></i> ${msg}</td></tr>`;
    }

    function escHtml(str) {
        const d = document.createElement('div');
        d.textContent = str || '';
        return d.innerHTML;
    }

    addBtn.addEventListener('click', openAdd);
    saveBtn.addEventListener('click', save);
    searchInput.addEventListener('input', e => render(e.target.value));

    load();
});

document.addEventListener('DOMContentLoaded', () => {
    const tbody        = document.getElementById('jobOrdersTableBody');
    const searchInput  = document.getElementById('jobSearch');
    const statusFilter = document.getElementById('jobStatusFilter');
    const addBtn       = document.getElementById('addJobBtn');
    const saveBtn      = document.getElementById('jobSaveBtn');
    const modalEl      = document.getElementById('jobModal');
    const modal        = new bootstrap.Modal(modalEl);
    const customerSel  = document.getElementById('jobCustomerId');
    const vehicleSel   = document.getElementById('jobVehicleId');
    const addItemBtn   = document.getElementById('addJobItemBtn');
    const jobItemsList = document.getElementById('jobItemsList');
    const jobTotalEl   = document.getElementById('jobTotal');

    let jobOrders = [];
    let customers = [];
    let allVehicles = [];
    let jobItems = [];
    let editingId = null;

    const STATUS_CLASSES = {
        'Pending':     'dd-badge-amber',
        'In Progress': 'dd-badge-blue',
        'Completed':   'dd-badge-green',
        'Cancelled':   'dd-badge-gray',
    };

    function load() {
        Promise.all([
            fetch('/api/job-orders').then(r => r.json()),
            fetch('/api/customers').then(r => r.json()),
            fetch('/api/vehicles').then(r => r.json()),
        ])
        .then(([jo, c, v]) => {
            jobOrders   = jo;
            customers   = c;
            allVehicles = v;
            populateCustomerSelect('');
            render();
        })
        .catch(() => showError('Failed to load job orders.'));
    }

    function populateCustomerSelect(selectedId) {
        customerSel.innerHTML = '<option value="">Select customer…</option>';
        customers.forEach(c => {
            const opt = document.createElement('option');
            opt.value = c.id;
            opt.textContent = c.name;
            if (String(c.id) === String(selectedId)) opt.selected = true;
            customerSel.appendChild(opt);
        });
    }

    function populateVehicleSelect(customerId, selectedId) {
        vehicleSel.innerHTML = '<option value="">(No vehicle / walk-in)</option>';
        vehicleSel.disabled = !customerId;
        if (!customerId) return;
        const myVehicles = allVehicles.filter(v => String(v.customer_id) === String(customerId));
        myVehicles.forEach(v => {
            const opt = document.createElement('option');
            opt.value = v.id;
            opt.textContent = `${v.year || ''} ${v.make} ${v.model} — ${v.plate}`.trim();
            if (String(v.id) === String(selectedId)) opt.selected = true;
            vehicleSel.appendChild(opt);
        });
    }

    customerSel.addEventListener('change', () => {
        populateVehicleSelect(customerSel.value, '');
    });

    function render() {
        const term   = searchInput.value.toLowerCase();
        const status = statusFilter.value;

        const list = jobOrders.filter(jo => {
            const matchSearch = !term ||
                jo.order_number.toLowerCase().includes(term) ||
                jo.customer_name.toLowerCase().includes(term) ||
                (jo.vehicle_plate || '').toLowerCase().includes(term);
            const matchStatus = !status || jo.status === status;
            return matchSearch && matchStatus;
        });

        tbody.innerHTML = '';
        if (!list.length) {
            tbody.innerHTML = `<tr><td colspan="8" class="dd-table-empty">
                <i class="fas fa-clipboard-list"></i> No job orders found.</td></tr>`;
            return;
        }

        list.forEach(jo => {
            const badgeClass = STATUS_CLASSES[jo.status] || 'dd-badge-gray';
            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td><span style="font-family:monospace;font-weight:600;font-size:.8rem;">${escHtml(jo.order_number)}</span></td>
                <td style="font-weight:500;">${escHtml(jo.customer_name)}</td>
                <td style="color:var(--text-muted);">${escHtml(jo.vehicle_display) || '<em style="color:#cbd5e1;">—</em>'}</td>
                <td style="color:var(--text-muted);">${escHtml(jo.assigned_to) || '<em style="color:#cbd5e1;">—</em>'}</td>
                <td><span class="dd-badge ${badgeClass}">${jo.status}</span></td>
                <td style="text-align:right;font-weight:600;color:var(--primary);">₱${parseFloat(jo.total || 0).toFixed(2)}</td>
                <td style="color:var(--text-muted);font-size:.8rem;">${formatDate(jo.created_at)}</td>
                <td style="text-align:center;">
                    <div class="dd-actions" style="justify-content:center;">
                        <button class="dd-btn-icon edit" title="Edit" data-id="${jo.id}">
                            <i class="fas fa-pencil"></i>
                        </button>
                        <button class="dd-btn-icon delete" title="Delete" data-id="${jo.id}">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                </td>
            `;
            tr.querySelector('.edit').addEventListener('click', () => openEdit(jo.id));
            tr.querySelector('.delete').addEventListener('click', () => deleteJob(jo.id, jo.order_number));
            tbody.appendChild(tr);
        });
    }

    function openAdd() {
        editingId = null;
        document.getElementById('jobModalTitle').textContent = 'New Job Order';
        clearForm();
        modal.show();
    }

    function openEdit(id) {
        fetch(`/api/job-orders/${id}`)
            .then(r => r.json())
            .then(jo => {
                editingId = id;
                document.getElementById('jobModalTitle').textContent = `Edit ${jo.order_number}`;
                populateCustomerSelect(jo.customer_id);
                populateVehicleSelect(jo.customer_id, jo.vehicle_id);
                document.getElementById('jobStatus').value     = jo.status;
                document.getElementById('jobAssignedTo').value = jo.assigned_to || '';
                document.getElementById('jobNotes').value      = jo.notes || '';
                jobItems = (jo.items || []).map(i => ({ ...i }));
                renderJobItems();
                modal.show();
            });
    }

    function save() {
        const customer_id  = customerSel.value;
        const vehicle_id   = vehicleSel.value || null;
        const status       = document.getElementById('jobStatus').value;
        const assigned_to  = document.getElementById('jobAssignedTo').value.trim();
        const notes        = document.getElementById('jobNotes').value.trim();

        if (!customer_id) { alert('Please select a customer.'); return; }

        const payload = {
            customer_id: parseInt(customer_id),
            vehicle_id: vehicle_id ? parseInt(vehicle_id) : null,
            status, assigned_to, notes,
            items: jobItems.map(i => ({
                item_name: i.item_name,
                item_type: i.item_type,
                price: parseFloat(i.price),
                quantity: parseInt(i.quantity),
            })),
        };

        const url    = editingId ? `/api/job-orders/${editingId}` : '/api/job-orders';
        const method = editingId ? 'PUT' : 'POST';

        fetch(url, {
            method,
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        })
        .then(r => { if (!r.ok) return r.json().then(e => { throw new Error(e.error); }); return r.json(); })
        .then(() => { modal.hide(); load(); })
        .catch(err => alert(err.message));
    }

    function deleteJob(id, orderNum) {
        if (!confirm(`Delete job order "${orderNum}"?`)) return;
        fetch(`/api/job-orders/${id}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(() => load())
            .catch(err => alert(err.message));
    }

    function renderJobItems() {
        jobItemsList.innerHTML = '';
        if (!jobItems.length) {
            jobItemsList.innerHTML = '<p style="font-size:.8rem;color:var(--text-muted);font-style:italic;">No items yet. Add a service or product below.</p>';
            updateTotal();
            return;
        }

        jobItems.forEach((item, idx) => {
            const row = document.createElement('div');
            row.style.cssText = 'display:grid;grid-template-columns:1fr 90px 90px 70px 32px;gap:8px;margin-bottom:8px;align-items:center;';
            row.innerHTML = `
                <input class="dd-form-control" placeholder="Service / item name" value="${escHtml(item.item_name)}" style="font-size:.8rem;padding:6px 10px;"/>
                <select class="dd-form-control" style="font-size:.8rem;padding:6px 8px;">
                    <option value="Service" ${item.item_type === 'Service' ? 'selected' : ''}>Service</option>
                    <option value="Product" ${item.item_type === 'Product' ? 'selected' : ''}>Product</option>
                </select>
                <input type="number" class="dd-form-control" placeholder="Price" value="${item.price}" min="0" step="0.01" style="font-size:.8rem;padding:6px 10px;"/>
                <input type="number" class="dd-form-control" placeholder="Qty" value="${item.quantity}" min="1" style="font-size:.8rem;padding:6px 10px;"/>
                <button class="dd-btn-icon delete" title="Remove"><i class="fas fa-xmark"></i></button>
            `;
            const [nameIn, typeIn, priceIn, qtyIn] = row.querySelectorAll('input, select');
            nameIn.addEventListener('input',  e => { jobItems[idx].item_name = e.target.value; });
            typeIn.addEventListener('change', e => { jobItems[idx].item_type  = e.target.value; });
            priceIn.addEventListener('input', e => { jobItems[idx].price = e.target.value; updateTotal(); });
            qtyIn.addEventListener('input',   e => { jobItems[idx].quantity = e.target.value; updateTotal(); });
            row.querySelector('.delete').addEventListener('click', () => {
                jobItems.splice(idx, 1);
                renderJobItems();
            });
            jobItemsList.appendChild(row);
        });

        updateTotal();
    }

    function updateTotal() {
        const total = jobItems.reduce((s, i) => s + (parseFloat(i.price) || 0) * (parseInt(i.quantity) || 1), 0);
        jobTotalEl.textContent = `₱${total.toFixed(2)}`;
    }

    function clearForm() {
        populateCustomerSelect('');
        populateVehicleSelect('', '');
        document.getElementById('jobStatus').value     = 'Pending';
        document.getElementById('jobAssignedTo').value = '';
        document.getElementById('jobNotes').value      = '';
        jobItems = [];
        renderJobItems();
    }

    function formatDate(iso) {
        if (!iso) return '—';
        const d = new Date(iso);
        return d.toLocaleDateString('en-PH', { month: 'short', day: 'numeric', year: 'numeric' });
    }

    function showError(msg) {
        tbody.innerHTML = `<tr><td colspan="8" class="dd-table-empty" style="color:var(--danger);">
            <i class="fas fa-circle-exclamation"></i> ${msg}</td></tr>`;
    }

    function escHtml(str) {
        const d = document.createElement('div');
        d.textContent = str || '';
        return d.innerHTML;
    }

    addItemBtn.addEventListener('click', () => {
        jobItems.push({ item_name: '', item_type: 'Service', price: 0, quantity: 1 });
        renderJobItems();
    });

    addBtn.addEventListener('click', openAdd);
    saveBtn.addEventListener('click', save);
    searchInput.addEventListener('input', render);
    statusFilter.addEventListener('change', render);

    load();
});

document.addEventListener('DOMContentLoaded', function () {
    const toggleButtons    = document.querySelectorAll('.dd-tab');
    const servicesSection  = document.getElementById('services-section');
    const productsSection  = document.getElementById('products-section');
    const servicesTableBody = document.getElementById('servicesTableBody');
    const productsTableBody = document.getElementById('productsTableBody');

    const productModal  = new bootstrap.Modal(document.getElementById('productModal'));
    const serviceModal  = new bootstrap.Modal(document.getElementById('serviceModal'));

    let editingProductId = null;
    let editingServiceId = null;

    // ── Toggle tabs ───────────────────────────────────────────────
    toggleButtons.forEach(btn => {
        btn.addEventListener('click', function () {
            toggleButtons.forEach(b => b.classList.remove('active'));
            this.classList.add('active');
            const section = this.getAttribute('data-section');
            servicesSection.classList.remove('active');
            productsSection.classList.remove('active');
            document.getElementById(section + '-section').classList.add('active');
        });
    });

    // ── Category selects ──────────────────────────────────────────
    fetch('/api/product-categories')
        .then(r => r.json())
        .then(cats => {
            const sel = document.getElementById('productCategory');
            sel.innerHTML = '<option selected>Select category</option>';
            cats.forEach(c => {
                const o = document.createElement('option'); o.value = c; o.textContent = c;
                sel.appendChild(o);
            });
        });

    fetch('/api/service-categories')
        .then(r => r.json())
        .then(cats => {
            const sel = document.getElementById('serviceCategory');
            sel.innerHTML = '<option selected>Select category</option>';
            cats.forEach(c => {
                const o = document.createElement('option'); o.value = c; o.textContent = c;
                sel.appendChild(o);
            });
        });

    // ── Add Item Button ───────────────────────────────────────────
    document.getElementById('addItemButton').addEventListener('click', () => {
        const active = document.querySelector('.dd-tab.active')?.getAttribute('data-section');
        if (active === 'products') {
            clearProductForm(); editingProductId = null; productModal.show();
        } else {
            clearServiceForm(); editingServiceId = null; serviceModal.show();
        }
    });

    // ── Load tables ───────────────────────────────────────────────
    function loadProducts() {
        fetch('/api/products')
            .then(r => r.json())
            .then(products => {
                productsTableBody.innerHTML = '';
                if (!products.length) {
                    productsTableBody.innerHTML = '<tr><td colspan="6" class="dd-table-empty"><i class="fas fa-box"></i> No products yet.</td></tr>';
                    return;
                }
                products.forEach(p => {
                    const img = p.image_path && p.image_path !== 'null'
                        ? `/static/assets/images/uploads/${p.image_path}`
                        : 'https://placehold.co/60x60/EEE/31343C';
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td><img src="${img}" class="dd-table-img" alt="${p.name}"/></td>
                        <td style="font-weight:600;">${p.name}</td>
                        <td><span class="dd-badge dd-badge-gray">${p.category || ''}</span></td>
                        <td style="text-align:right;font-weight:600;">₱${parseFloat(p.price).toFixed(2)}</td>
                        <td style="text-align:center;">
                            ${p.quantity <= 5
                                ? `<span class="dd-badge dd-badge-red">${p.quantity}</span>`
                                : `<span class="dd-badge dd-badge-green">${p.quantity}</span>`
                            }
                        </td>
                        <td style="text-align:center;">
                            <div class="dd-actions" style="justify-content:center;">
                                <button class="dd-btn-icon edit" data-id="${p.id}" title="Edit"><i class="fas fa-pencil"></i></button>
                                <button class="dd-btn-icon delete" data-id="${p.id}" title="Delete"><i class="fas fa-trash"></i></button>
                            </div>
                        </td>
                    `;
                    tr.querySelector('.edit').addEventListener('click', () => onEditProduct(p.id));
                    tr.querySelector('.delete').addEventListener('click', () => onDeleteProduct(p.id));
                    productsTableBody.appendChild(tr);
                });
            });
    }

    function loadServices() {
        fetch('/api/services')
            .then(r => r.json())
            .then(services => {
                servicesTableBody.innerHTML = '';
                if (!services.length) {
                    servicesTableBody.innerHTML = '<tr><td colspan="5" class="dd-table-empty"><i class="fas fa-wrench"></i> No services yet.</td></tr>';
                    return;
                }
                services.forEach(s => {
                    const img = s.image_path && s.image_path !== 'null'
                        ? `/static/assets/images/uploads/${s.image_path}`
                        : 'https://placehold.co/60x60/EEE/31343C';
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td><img src="${img}" class="dd-table-img" alt="${s.name}"/></td>
                        <td style="font-weight:600;">${s.name}</td>
                        <td><span class="dd-badge dd-badge-blue">${s.category}</span></td>
                        <td style="text-align:right;font-weight:600;">₱${parseFloat(s.price).toFixed(2)}</td>
                        <td style="text-align:center;">
                            <div class="dd-actions" style="justify-content:center;">
                                <button class="dd-btn-icon edit" data-id="${s.id}" title="Edit"><i class="fas fa-pencil"></i></button>
                                <button class="dd-btn-icon delete" data-id="${s.id}" title="Delete"><i class="fas fa-trash"></i></button>
                            </div>
                        </td>
                    `;
                    tr.querySelector('.edit').addEventListener('click', () => onEditService(s.id));
                    tr.querySelector('.delete').addEventListener('click', () => onDeleteService(s.id));
                    servicesTableBody.appendChild(tr);
                });
            });
    }

    // ── Edit / Delete handlers ────────────────────────────────────
    function onEditProduct(id) {
        fetch(`/api/products/${id}`)
            .then(r => r.json())
            .then(p => {
                editingProductId = p.id;
                document.getElementById('productName').value      = p.name;
                document.getElementById('productCategory').value  = p.category || 'Select category';
                document.getElementById('productSalePrice').value = p.price;
                document.getElementById('productQuantity').value  = p.quantity;
                document.getElementById('productModalLabel').textContent = 'Edit Product';
                productModal.show();
            });
    }

    function onEditService(id) {
        fetch(`/api/services/${id}`)
            .then(r => r.json())
            .then(s => {
                editingServiceId = s.id;
                document.getElementById('serviceName').value      = s.name;
                document.getElementById('serviceCategory').value  = s.category || 'Select category';
                document.getElementById('serviceSalePrice').value = s.price;
                document.getElementById('serviceModalLabel').textContent = 'Edit Service';
                serviceModal.show();
            });
    }

    function onDeleteProduct(id) {
        if (!confirm('Delete this product?')) return;
        fetch(`/api/products/${id}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(d => { if (d.error) alert(d.error); else loadProducts(); });
    }

    function onDeleteService(id) {
        if (!confirm('Delete this service?')) return;
        fetch(`/api/services/${id}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(d => { if (d.error) alert(d.error); else loadServices(); });
    }

    // ── Save handlers ─────────────────────────────────────────────
    document.getElementById('productSaveBtn').addEventListener('click', () => {
        const name     = document.getElementById('productName').value.trim();
        const category = document.getElementById('productCategory').value;
        const price    = parseFloat(document.getElementById('productSalePrice').value);
        const quantity = parseInt(document.getElementById('productQuantity').value);

        if (!name || isNaN(price) || isNaN(quantity)) {
            alert('Please fill in all required fields.');
            return;
        }

        const formData = new FormData();
        formData.append('name', name);
        formData.append('category', category);
        formData.append('price', price);
        formData.append('quantity', quantity);
        const fileInput = document.getElementById('productFileInput');
        if (fileInput.files.length > 0) formData.append('image', fileInput.files[0]);

        const url    = editingProductId ? `/api/products/${editingProductId}` : '/api/products';
        const method = editingProductId ? 'PUT' : 'POST';

        fetch(url, { method, body: formData })
            .then(r => r.json())
            .then(d => {
                if (d.error) { alert(d.error); return; }
                editingProductId = null;
                productModal.hide();
                loadProducts();
                document.getElementById('productModalLabel').textContent = 'Product Details';
            });
    });

    document.getElementById('serviceSaveBtn').addEventListener('click', () => {
        const name     = document.getElementById('serviceName').value.trim();
        const category = document.getElementById('serviceCategory').value;
        const price    = parseFloat(document.getElementById('serviceSalePrice').value);

        if (!name || isNaN(price)) {
            alert('Please fill in all required fields.');
            return;
        }

        const formData = new FormData();
        formData.append('name', name);
        formData.append('category', category);
        formData.append('price', price);
        const fileInput = document.getElementById('serviceFileInput');
        if (fileInput.files.length > 0) formData.append('image', fileInput.files[0]);

        const url    = editingServiceId ? `/api/services/${editingServiceId}` : '/api/services';
        const method = editingServiceId ? 'PUT' : 'POST';

        fetch(url, { method, body: formData })
            .then(r => r.json())
            .then(d => {
                if (d.error) { alert(d.error); return; }
                editingServiceId = null;
                serviceModal.hide();
                loadServices();
                document.getElementById('serviceModalLabel').textContent = 'Service Details';
            });
    });

    // ── Image preview ─────────────────────────────────────────────
    document.getElementById('productFileButton').addEventListener('click', () => document.getElementById('productFileInput').click());
    document.getElementById('productFileInput').addEventListener('change', function () {
        const file = this.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = e => {
            document.getElementById('productPreviewImage').src = e.target.result;
            document.getElementById('productRemoveImage').style.display = 'inline-flex';
        };
        reader.readAsDataURL(file);
    });
    document.getElementById('productRemoveImage').addEventListener('click', function () {
        document.getElementById('productFileInput').value = '';
        document.getElementById('productPreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        this.style.display = 'none';
    });

    document.getElementById('serviceFileButton').addEventListener('click', () => document.getElementById('serviceFileInput').click());
    document.getElementById('serviceFileInput').addEventListener('change', function () {
        const file = this.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = e => {
            document.getElementById('servicePreviewImage').src = e.target.result;
            document.getElementById('serviceRemoveImage').style.display = 'inline-flex';
        };
        reader.readAsDataURL(file);
    });
    document.getElementById('serviceRemoveImage').addEventListener('click', function () {
        document.getElementById('serviceFileInput').value = '';
        document.getElementById('servicePreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        this.style.display = 'none';
    });

    // ── Helpers ───────────────────────────────────────────────────
    function clearProductForm() {
        document.getElementById('productForm').reset();
        document.getElementById('productPreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        document.getElementById('productRemoveImage').style.display = 'none';
        document.getElementById('productModalLabel').textContent = 'Product Details';
    }

    function clearServiceForm() {
        document.getElementById('serviceForm').reset();
        document.getElementById('servicePreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        document.getElementById('serviceRemoveImage').style.display = 'none';
        document.getElementById('serviceModalLabel').textContent = 'Service Details';
    }

    // ── Initial load ──────────────────────────────────────────────
    loadServices();
    loadProducts();
});

