document.addEventListener('DOMContentLoaded', function () {
    const toggleButtons     = document.querySelectorAll('.dd-tab');
    const servicesSection   = document.getElementById('services-section');
    const productsSection   = document.getElementById('products-section');
    const servicesTableBody = document.getElementById('servicesTableBody');
    const productsTableBody = document.getElementById('productsTableBody');

    const productModal = new bootstrap.Modal(document.getElementById('productModal'));
    const serviceModal = new bootstrap.Modal(document.getElementById('serviceModal'));

    let editingProductId = null;
    let editingServiceId = null;

    // ── Toggle tabs ───────────────────────────────────────────────
    toggleButtons.forEach(btn => {
        btn.addEventListener('click', function () {
            toggleButtons.forEach(b => b.classList.remove('active'));
            this.classList.add('active');
            const section = this.getAttribute('data-section');
            servicesSection.classList.remove('active');
            productsSection.classList.remove('active');
            document.getElementById(section + '-section').classList.add('active');
        });
    });

    // ── Category selects ──────────────────────────────────────────
    fetch('/api/product-categories')
        .then(r => r.json())
        .then(cats => {
            const sel = document.getElementById('productCategory');
            sel.innerHTML = '<option selected>Select category</option>';
            cats.forEach(c => {
                const o = document.createElement('option'); o.value = c; o.textContent = c;
                sel.appendChild(o);
            });
        });

    fetch('/api/service-categories')
        .then(r => r.json())
        .then(cats => {
            const sel = document.getElementById('serviceCategory');
            sel.innerHTML = '<option selected>Select category</option>';
            cats.forEach(c => {
                const o = document.createElement('option'); o.value = c; o.textContent = c;
                sel.appendChild(o);
            });
        });

    // ── Add Item Button ───────────────────────────────────────────
    document.getElementById('addItemButton').addEventListener('click', () => {
        const active = document.querySelector('.dd-tab.active')?.getAttribute('data-section');
        if (active === 'products') {
            clearProductForm(); editingProductId = null; productModal.show();
        } else {
            clearServiceForm(); editingServiceId = null; serviceModal.show();
        }
    });

    // ── Load tables ───────────────────────────────────────────────
    function loadProducts() {
        fetch('/api/products')
            .then(r => r.json())
            .then(products => {
                productsTableBody.innerHTML = '';
                if (!products.length) {
                    productsTableBody.innerHTML = '<tr><td colspan="6" class="dd-table-empty"><i class="fas fa-box"></i> No products yet.</td></tr>';
                    return;
                }
                products.forEach(p => {
                    const img = p.image_path && p.image_path !== 'null'
                        ? `/static/assets/images/uploads/${p.image_path}`
                        : 'https://placehold.co/60x60/EEE/31343C';
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td><img src="${img}" class="dd-table-img" alt="${p.name}"/></td>
                        <td style="font-weight:600;">${p.name}</td>
                        <td><span class="dd-badge dd-badge-gray">${p.category || ''}</span></td>
                        <td style="text-align:right;font-weight:600;">₱${parseFloat(p.price).toFixed(2)}</td>
                        <td style="text-align:center;">
                            ${p.quantity <= 5
                                ? `<span class="dd-badge dd-badge-red">${p.quantity}</span>`
                                : `<span class="dd-badge dd-badge-green">${p.quantity}</span>`}
                        </td>
                        <td style="text-align:center;">
                            <div class="dd-actions" style="justify-content:center;">
                                <button class="dd-btn-icon edit" data-id="${p.id}" title="Edit"><i class="fas fa-pencil"></i></button>
                                <button class="dd-btn-icon delete" data-id="${p.id}" title="Delete"><i class="fas fa-trash"></i></button>
                            </div>
                        </td>
                    `;
                    tr.querySelector('.edit').addEventListener('click', () => onEditProduct(p.id));
                    tr.querySelector('.delete').addEventListener('click', () => onDeleteProduct(p.id));
                    productsTableBody.appendChild(tr);
                });
            });
    }

    function loadServices() {
        fetch('/api/services')
            .then(r => r.json())
            .then(services => {
                servicesTableBody.innerHTML = '';
                if (!services.length) {
                    servicesTableBody.innerHTML = '<tr><td colspan="5" class="dd-table-empty"><i class="fas fa-wrench"></i> No services yet.</td></tr>';
                    return;
                }
                services.forEach(s => {
                    const img = s.image_path && s.image_path !== 'null'
                        ? `/static/assets/images/uploads/${s.image_path}`
                        : 'https://placehold.co/60x60/EEE/31343C';
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td><img src="${img}" class="dd-table-img" alt="${s.name}"/></td>
                        <td style="font-weight:600;">${s.name}</td>
                        <td><span class="dd-badge dd-badge-blue">${s.category}</span></td>
                        <td style="text-align:right;font-weight:600;">₱${parseFloat(s.price).toFixed(2)}</td>
                        <td style="text-align:center;">
                            <div class="dd-actions" style="justify-content:center;">
                                <button class="dd-btn-icon edit" data-id="${s.id}" title="Edit"><i class="fas fa-pencil"></i></button>
                                <button class="dd-btn-icon delete" data-id="${s.id}" title="Delete"><i class="fas fa-trash"></i></button>
                            </div>
                        </td>
                    `;
                    tr.querySelector('.edit').addEventListener('click', () => onEditService(s.id));
                    tr.querySelector('.delete').addEventListener('click', () => onDeleteService(s.id));
                    servicesTableBody.appendChild(tr);
                });
            });
    }

    // ── Edit handlers ─────────────────────────────────────────────
    function onEditProduct(id) {
        fetch(`/api/products/${id}`)
            .then(r => r.json())
            .then(p => {
                editingProductId = p.id;
                document.getElementById('productName').value      = p.name;
                document.getElementById('productCategory').value  = p.category || 'Select category';
                document.getElementById('productSalePrice').value = p.price;
                document.getElementById('productQuantity').value  = p.quantity;
                document.getElementById('productModalLabel').textContent = 'Edit Product';
                productModal.show();
            });
    }

    function onEditService(id) {
        fetch(`/api/services/${id}`)
            .then(r => r.json())
            .then(s => {
                editingServiceId = s.id;
                document.getElementById('serviceName').value      = s.name;
                document.getElementById('serviceCategory').value  = s.category || 'Select category';
                document.getElementById('serviceSalePrice').value = s.price;
                document.getElementById('serviceModalLabel').textContent = 'Edit Service';
                serviceModal.show();
            });
    }

    function onDeleteProduct(id) {
        if (!confirm('Delete this product?')) return;
        fetch(`/api/products/${id}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(d => { if (d.error) alert(d.error); else loadProducts(); });
    }

    function onDeleteService(id) {
        if (!confirm('Delete this service?')) return;
        fetch(`/api/services/${id}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(d => { if (d.error) alert(d.error); else loadServices(); });
    }

    // ── Save handlers ─────────────────────────────────────────────
    document.getElementById('productSaveBtn').addEventListener('click', () => {
        const name     = document.getElementById('productName').value.trim();
        const category = document.getElementById('productCategory').value;
        const price    = parseFloat(document.getElementById('productSalePrice').value);
        const quantity = parseInt(document.getElementById('productQuantity').value);

        if (!name || isNaN(price) || isNaN(quantity)) {
            alert('Please fill in all required fields.');
            return;
        }

        const formData = new FormData();
        formData.append('name', name);
        formData.append('category', category);
        formData.append('price', price);
        formData.append('quantity', quantity);
        const fileInput = document.getElementById('productFileInput');
        if (fileInput.files.length > 0) formData.append('image', fileInput.files[0]);

        const url    = editingProductId ? `/api/products/${editingProductId}` : '/api/products';
        const method = editingProductId ? 'PUT' : 'POST';

        fetch(url, { method, body: formData })
            .then(r => r.json())
            .then(d => {
                if (d.error) { alert(d.error); return; }
                editingProductId = null;
                productModal.hide();
                loadProducts();
                document.getElementById('productModalLabel').textContent = 'Product Details';
            });
    });

    document.getElementById('serviceSaveBtn').addEventListener('click', () => {
        const name     = document.getElementById('serviceName').value.trim();
        const category = document.getElementById('serviceCategory').value;
        const price    = parseFloat(document.getElementById('serviceSalePrice').value);

        if (!name || isNaN(price)) {
            alert('Please fill in all required fields.');
            return;
        }

        const formData = new FormData();
        formData.append('name', name);
        formData.append('category', category);
        formData.append('price', price);
        const fileInput = document.getElementById('serviceFileInput');
        if (fileInput.files.length > 0) formData.append('image', fileInput.files[0]);

        const url    = editingServiceId ? `/api/services/${editingServiceId}` : '/api/services';
        const method = editingServiceId ? 'PUT' : 'POST';

        fetch(url, { method, body: formData })
            .then(r => r.json())
            .then(d => {
                if (d.error) { alert(d.error); return; }
                editingServiceId = null;
                serviceModal.hide();
                loadServices();
                document.getElementById('serviceModalLabel').textContent = 'Service Details';
            });
    });

    // ── Image preview ─────────────────────────────────────────────
    document.getElementById('productFileButton').addEventListener('click', () =>
        document.getElementById('productFileInput').click());
    document.getElementById('productFileInput').addEventListener('change', function () {
        const file = this.files[0]; if (!file) return;
        const reader = new FileReader();
        reader.onload = e => {
            document.getElementById('productPreviewImage').src = e.target.result;
            document.getElementById('productRemoveImage').style.display = 'inline-flex';
        };
        reader.readAsDataURL(file);
    });
    document.getElementById('productRemoveImage').addEventListener('click', function () {
        document.getElementById('productFileInput').value = '';
        document.getElementById('productPreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        this.style.display = 'none';
    });

    document.getElementById('serviceFileButton').addEventListener('click', () =>
        document.getElementById('serviceFileInput').click());
    document.getElementById('serviceFileInput').addEventListener('change', function () {
        const file = this.files[0]; if (!file) return;
        const reader = new FileReader();
        reader.onload = e => {
            document.getElementById('servicePreviewImage').src = e.target.result;
            document.getElementById('serviceRemoveImage').style.display = 'inline-flex';
        };
        reader.readAsDataURL(file);
    });
    document.getElementById('serviceRemoveImage').addEventListener('click', function () {
        document.getElementById('serviceFileInput').value = '';
        document.getElementById('servicePreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        this.style.display = 'none';
    });

    // ── Helpers ───────────────────────────────────────────────────
    function clearProductForm() {
        document.getElementById('productForm').reset();
        document.getElementById('productPreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        document.getElementById('productRemoveImage').style.display = 'none';
        document.getElementById('productModalLabel').textContent = 'Product Details';
    }

    function clearServiceForm() {
        document.getElementById('serviceForm').reset();
        document.getElementById('servicePreviewImage').src = 'https://placehold.co/80x80/EEE/31343C';
        document.getElementById('serviceRemoveImage').style.display = 'none';
        document.getElementById('serviceModalLabel').textContent = 'Service Details';
    }

    // ── Initial load ──────────────────────────────────────────────
    loadServices();
    loadProducts();
});

document.addEventListener('DOMContentLoaded', () => {
    const modal              = document.getElementById("myModal");
    const invoiceModalEl     = document.getElementById("invoiceModal");
    const addTransactionButton = document.getElementById("addTransactionButton");
    const productSearch      = document.getElementById("productSearch");
    const categorySelect     = document.getElementById("categorySelect");
    const orderDateInput     = document.getElementById("orderDate");
    const customerNameInput  = document.getElementById("customername");
    const productGrid        = document.getElementById("productGrid");
    const cartItemsContainer = document.getElementById("cartItems");
    const grandTotalElement  = document.getElementById("grandTotal");
    const paymentInput       = document.getElementById("payment");
    const changeOutput       = document.getElementById("change");
    const finalizeCheckoutBtn = document.getElementById("finalizeCheckoutBtn");
    const purchaseTableBody  = document.getElementById("purchaseTableBody");

    let products = [], services = [], cart = [], purchases = [];
    let currentOrderDate = "", currentCustomerName = "", editingTransactionId = null;

    fetchItemsFromDB();
    fetchTransactionsFromDB();

    function fetchItemsFromDB() {
        Promise.all([
            fetch('/api/products').then(r => r.json()),
            fetch('/api/services').then(r => r.json())
        ])
        .then(([pd, sd]) => {
            products = pd; services = sd;
            populateCategories();
            renderItems();
        })
        .catch(err => console.error('Failed to fetch items:', err));
    }

    function fetchTransactionsFromDB() {
        fetch('/api/transactions')
            .then(r => r.json())
            .then(data => { purchases = data; updatePurchaseList(); })
            .catch(err => console.error('Failed to fetch transactions:', err));
    }

    function populateCategories() {
        if (!categorySelect) return;
        const existing = categorySelect.value;
        categorySelect.innerHTML = "";
        const cats = ["All", ...new Set([
            ...products.map(p => p.category),
            ...services.map(s => s.category)
        ])];
        cats.forEach(c => {
            const o = document.createElement("option");
            o.value = c; o.textContent = c;
            categorySelect.appendChild(o);
        });
        if (existing) categorySelect.value = existing;
    }

    function generateTransactionId() {
        return String(Date.now()).slice(-6);
    }

    function renderItems() {
        if (!productGrid) return;
        productGrid.innerHTML = "";
        const cat  = categorySelect ? categorySelect.value : "All";
        const term = productSearch  ? productSearch.value.toLowerCase() : "";
        const items = [
            ...products.map(p => ({ ...p, itemType: "product" })),
            ...services.map(s => ({ ...s, itemType: "service" }))
        ];
        items
            .filter(i => i.name.toLowerCase().includes(term) && (cat === "All" || i.category === cat))
            .forEach(item => {
                const card = document.createElement("div");
                card.className = "dd-product-card";
                const imgSrc = item.image_path
                    ? `/static/assets/images/uploads/${item.image_path}`
                    : 'https://placehold.co/80x80/EEE/31343C';
                card.innerHTML = `
                    <img src="${imgSrc}" alt="${item.name}"/>
                    <h4>${item.name}</h4>
                    <p>₱${parseFloat(item.price).toFixed(2)}</p>
                    <button>Add to Cart</button>
                `;
                productGrid.appendChild(card);
                card.querySelector("button").addEventListener("click", () => {
                    item.itemType === "product" ? addToCart(item.id) : addServiceToCart(item.id);
                });
            });
    }

    function renderCart() {
        if (!cartItemsContainer) return;
        cartItemsContainer.innerHTML = "";
        cart.forEach(ci => {
            const entity = ci.product || ci.service;
            const div = document.createElement("div");
            div.className = "list-group-item d-flex justify-content-between align-items-center";
            div.style.cssText = "font-size:.85rem;padding:8px 12px;";
            div.innerHTML = `
                <div>${entity.name} <span class="badge bg-secondary rounded-pill">×${ci.quantity}</span></div>
                <div style="display:flex;align-items:center;gap:8px;">
                    <span style="font-weight:600;color:var(--primary);">₱${(entity.price * ci.quantity).toFixed(2)}</span>
                    <button class="dd-btn-icon delete rm-btn" style="width:24px;height:24px;font-size:.75rem;">×</button>
                </div>
            `;
            div.querySelector(".rm-btn").addEventListener("click", () => {
                ci.product ? removeFromCart(entity.id) : removeServiceFromCart(entity.id);
            });
            cartItemsContainer.appendChild(div);
        });
    }

    function updatePaymentSummary() {
        const total = cart.reduce((s, ci) => s + (ci.product ? ci.product.price : ci.service.price) * ci.quantity, 0);
        if (grandTotalElement) grandTotalElement.textContent = `₱${total.toFixed(2)}`;
        calculateChange();
    }

    function calculateChange() {
        const total   = parseFloat(grandTotalElement?.textContent?.slice(1) || 0) || 0;
        const payment = parseFloat(paymentInput?.value || 0) || 0;
        if (changeOutput) changeOutput.textContent = `₱${(payment - total).toFixed(2)}`;
    }

    function addToCart(id) {
        const ex = cart.find(i => i.product?.id === id);
        if (ex) ex.quantity++;
        else { const p = products.find(p => p.id === id); if (p) cart.push({ product: p, quantity: 1 }); }
        renderCart(); updatePaymentSummary();
    }

    function addServiceToCart(id) {
        const ex = cart.find(i => i.service?.id === id);
        if (ex) ex.quantity++;
        else { const s = services.find(s => s.id === id); if (s) cart.push({ service: s, quantity: 1 }); }
        renderCart(); updatePaymentSummary();
    }

    function removeFromCart(id) {
        cart = cart.filter(i => !(i.product?.id === id));
        renderCart(); updatePaymentSummary();
    }

    function removeServiceFromCart(id) {
        cart = cart.filter(i => !(i.service?.id === id));
        renderCart(); updatePaymentSummary();
    }

    function checkout() {
        if (!cart.length) return alert("Your cart is empty!");
        if (!currentOrderDate) return alert("Please select an order date!");
        if (!currentCustomerName.trim()) return alert("Please enter the customer name!");

        const totalAmount     = cart.reduce((s, ci) => s + (ci.product ? ci.product.price : ci.service.price) * ci.quantity, 0);
        const transactionId   = editingTransactionId || generateTransactionId();

        const items = cart.map(ci => {
            const entity = ci.product || ci.service;
            return { name: entity.name, price: entity.price, quantity: ci.quantity, category: ci.product ? "Product" : "Service" };
        });

        const txData = {
            transaction_id: transactionId,
            customer_name: currentCustomerName,
            order_date: currentOrderDate,
            total_amount: totalAmount,
            items
        };

        fetch('/api/transaction', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(txData)
        })
        .then(r => { if (!r.ok) throw new Error("Failed to save transaction"); return r.json(); })
        .then(() => {
            const savedTx = { ...txData };
            resetModal();
            fetchTransactionsFromDB();
            bootstrap.Modal.getInstance(modal)?.hide();
            populateInvoice(savedTx);
            new bootstrap.Modal(invoiceModalEl).show();
        })
        .catch(err => alert(err.message));
    }

    function populateInvoice(data) {
        const fmtDate = d => {
            if (!d) return '';
            const [y, m, day] = d.split('-');
            return `${m}/${day}/${y}`;
        };
        const el = id => document.getElementById(id);
        if (el('invoiceDate'))          el('invoiceDate').textContent          = fmtDate(data.order_date);
        if (el('invoiceTransactionId')) el('invoiceTransactionId').textContent = data.transaction_id;
        if (el('invoiceCustomer'))      el('invoiceCustomer').textContent      = data.customer_name;

        const tbody = el('invoiceItemsBody');
        if (tbody) {
            tbody.innerHTML = '';
            (data.items || []).forEach(item => {
                const qty = item.quantity || 1;
                const amount = (parseFloat(item.price) * qty).toFixed(2);
                const tr = document.createElement('tr');
                tr.innerHTML = `
                    <td>${item.name}</td>
                    <td>${item.category}</td>
                    <td>₱${parseFloat(item.price).toFixed(2)}</td>
                    <td class="qty">${item.category === 'Service' ? '-' : qty}</td>
                    <td class="text-end">₱${amount}</td>
                `;
                tbody.appendChild(tr);
            });
        }

        const totalEl = el('invoiceGrandTotal');
        if (totalEl) totalEl.textContent = `₱${parseFloat(data.total_amount).toFixed(2)}`;
    }

    function editPurchase(transactionId) {
        const purchase = purchases.find(p => p.transaction_id === transactionId);
        if (!purchase) return;
        editingTransactionId = transactionId;
        cart = purchase.items.map(item => {
            const found = item.category === "Product"
                ? products.find(p => p.name === item.name)
                : services.find(s => s.name === item.name);
            if (!found) return null;
            return item.category === "Product" ? { product: found, quantity: item.quantity || 1 } : { service: found, quantity: item.quantity || 1 };
        }).filter(Boolean);
        currentOrderDate    = purchase.order_date;
        currentCustomerName = purchase.customer_name;
        if (orderDateInput)    orderDateInput.value    = currentOrderDate;
        if (customerNameInput) customerNameInput.value = currentCustomerName;
        renderCart(); updatePaymentSummary();
        new bootstrap.Modal(modal).show();
    }

    function viewInvoice(transactionId) {
        const purchase = purchases.find(p => p.transaction_id === transactionId);
        if (!purchase) return;
        populateInvoice(purchase);
        new bootstrap.Modal(invoiceModalEl).show();
    }

    function deletePurchase(transactionId) {
        if (!confirm("Delete this transaction?")) return;
        fetch(`/api/transaction/${transactionId}`, { method: 'DELETE' })
            .then(r => r.json())
            .then(() => {
                purchases = purchases.filter(p => p.transaction_id !== transactionId);
                updatePurchaseList();
            })
            .catch(err => alert(err.message));
    }

    function updatePurchaseList() {
        if (!purchaseTableBody) return;
        purchaseTableBody.innerHTML = "";

        if (!purchases.length) {
            purchaseTableBody.innerHTML = `<tr><td colspan="5" class="dd-table-empty">
                <i class="fas fa-receipt"></i> No transactions yet.</td></tr>`;
            return;
        }

        purchases.forEach(purchase => {
            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td><span style="font-family:monospace;font-weight:600;">#${purchase.transaction_id}</span></td>
                <td style="color:var(--text-muted);">${purchase.order_date}</td>
                <td style="font-weight:500;">${purchase.customer_name}</td>
                <td style="text-align:right;font-weight:600;color:var(--primary);">₱${parseFloat(purchase.total_amount).toFixed(2)}</td>
                <td style="text-align:center;">
                    <div class="dd-actions" style="justify-content:center;">
                        <button class="dd-btn-icon view view-btn" title="View Invoice"><i class="fas fa-receipt"></i></button>
                        <button class="dd-btn-icon edit edit-btn" title="Edit"><i class="fas fa-pencil"></i></button>
                        <button class="dd-btn-icon delete del-btn" title="Delete"><i class="fas fa-trash"></i></button>
                    </div>
                </td>
            `;
            tr.querySelector('.view-btn').addEventListener('click', () => viewInvoice(purchase.transaction_id));
            tr.querySelector('.edit-btn').addEventListener('click', () => editPurchase(purchase.transaction_id));
            tr.querySelector('.del-btn').addEventListener('click',  () => deletePurchase(purchase.transaction_id));
            purchaseTableBody.appendChild(tr);
        });
    }

    function resetModal() {
        cart = []; editingTransactionId = null;
        currentOrderDate = ""; currentCustomerName = "";
        if (orderDateInput)    orderDateInput.value    = "";
        if (customerNameInput) customerNameInput.value = "";
        if (paymentInput)      paymentInput.value      = "";
        if (changeOutput)      changeOutput.textContent = "₱0.00";
        if (categorySelect)    categorySelect.value     = "All";
        renderCart(); renderItems(); updatePaymentSummary();
    }

    if (productSearch)     productSearch.addEventListener("input", renderItems);
    if (categorySelect)    categorySelect.addEventListener("change", renderItems);
    if (orderDateInput)    orderDateInput.addEventListener("change", e => currentOrderDate = e.target.value);
