{% extends "base.html" %}
{% block title %}Reports | DetailDash{% endblock %}
{% block page_title %}Reports{% endblock %}
{% set active_page = "reports" %}

{% block extra_css %}
<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script>
<style>
  .dd-report-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    margin-bottom: 24px;
  }
  @media (max-width: 900px) {
    .dd-report-grid { grid-template-columns: 1fr; }
  }
  .dd-chart-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    overflow: hidden;
  }
  .dd-chart-header {
    padding: 14px 20px;
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: space-between;
  }
  .dd-chart-header .title { font-size: .92rem; font-weight: 700; color: var(--text); }
  .dd-chart-header .sub   { font-size: .75rem; color: var(--text-muted); margin-top: 2px; }
  .dd-chart-body { padding: 16px; }
  .dd-range-bar {
    display: flex; gap: 10px; align-items: center; flex-wrap: wrap;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 14px 20px;
    margin-bottom: 24px;
  }
  .dd-range-bar label { font-size: .82rem; font-weight: 600; color: var(--text-muted); }
  .dd-range-bar input[type=date] {
    font-family: inherit; font-size: .82rem;
    padding: 6px 10px; border: 1px solid var(--border);
    border-radius: 6px; background: var(--bg); color: var(--text);
    outline: none;
  }
  .dd-range-bar input[type=date]:focus { border-color: var(--primary); }
  .dd-range-presets { display: flex; gap: 6px; flex-wrap: wrap; }
  .dd-preset-btn {
    font-size: .75rem; padding: 4px 10px; border-radius: 20px;
    border: 1px solid var(--border); background: var(--bg);
    color: var(--text-muted); cursor: pointer; transition: all .15s;
  }
  .dd-preset-btn:hover, .dd-preset-btn.active {
    background: var(--primary); color: #fff; border-color: var(--primary);
  }
  .dd-summary-table { width: 100%; border-collapse: collapse; }
  .dd-summary-table th, .dd-summary-table td {
    padding: 9px 14px; font-size: .82rem; border-bottom: 1px solid var(--border);
    text-align: left;
  }
  .dd-summary-table th { font-weight: 700; color: var(--text-muted); background: var(--bg); }
  .dd-summary-table td:last-child, .dd-summary-table th:last-child { text-align: right; }
  .dd-summary-table tr:last-child td { border-bottom: none; }
  .dd-report-stat-row {
    display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; margin-bottom: 24px;
  }
  @media (max-width: 600px) { .dd-report-stat-row { grid-template-columns: 1fr; } }
</style>
{% endblock %}

{% block content %}
<div class="dd-page-header">
  <div>
    <h1>Reports</h1>
    <p>Revenue trends, top services, and category breakdowns.</p>
  </div>
</div>

<!-- Date Range Bar -->
<div class="dd-range-bar">
  <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
    <label>From</label>
    <input type="date" id="startDate"/>
    <label>To</label>
    <input type="date" id="endDate"/>
    <button class="dd-btn dd-btn-primary" id="applyRange" style="padding:6px 16px;font-size:.82rem;">
      <i class="fas fa-filter"></i> Apply
    </button>
  </div>
  <div class="dd-range-presets" style="margin-left:auto;">
    <button class="dd-preset-btn" data-days="7">7 days</button>
    <button class="dd-preset-btn active" data-days="30">30 days</button>
    <button class="dd-preset-btn" data-days="90">90 days</button>
    <button class="dd-preset-btn" data-days="365">1 year</button>
  </div>
</div>

<!-- Summary Stat Cards -->
<div class="dd-report-stat-row" id="summaryStats">
  <div class="dd-stat">
    <div class="dd-stat-icon blue"><i class="fas fa-peso-sign"></i></div>
    <div class="dd-stat-body">
      <div class="dd-stat-label">Total Revenue</div>
      <div class="dd-stat-value" id="statTotal">₱0.00</div>
      <div class="dd-stat-sub">In selected period</div>
    </div>
  </div>
  <div class="dd-stat">
    <div class="dd-stat-icon green"><i class="fas fa-receipt"></i></div>
    <div class="dd-stat-body">
      <div class="dd-stat-label">Transactions</div>
      <div class="dd-stat-value" id="statCount">0</div>
      <div class="dd-stat-sub">Completed sales</div>
    </div>
  </div>
  <div class="dd-stat">
    <div class="dd-stat-icon amber"><i class="fas fa-chart-line"></i></div>
    <div class="dd-stat-body">
      <div class="dd-stat-label">Avg per Transaction</div>
      <div class="dd-stat-value" id="statAvg">₱0.00</div>
      <div class="dd-stat-sub">Average sale value</div>
    </div>
  </div>
</div>

<!-- Charts Row -->
<div class="dd-report-grid">

  <!-- Daily Revenue Line Chart -->
  <div class="dd-chart-card" style="grid-column: 1 / -1;">
    <div class="dd-chart-header">
      <div>
        <div class="title">Daily Revenue</div>
        <div class="sub" id="dailyChartSub">Revenue per day in selected period</div>
      </div>
    </div>
    <div class="dd-chart-body">
      <canvas id="dailyRevenueChart" height="90"></canvas>
    </div>
  </div>

  <!-- Top Services / Products Bar Chart -->
  <div class="dd-chart-card">
    <div class="dd-chart-header">
      <div>
        <div class="title">Top 5 Items by Revenue</div>
        <div class="sub">Services &amp; products in selected period</div>
      </div>
    </div>
    <div class="dd-chart-body">
      <canvas id="topItemsChart" height="220"></canvas>
    </div>
  </div>

  <!-- Category Breakdown Table -->
  <div class="dd-chart-card">
    <div class="dd-chart-header">
      <div>
        <div class="title">Revenue by Category</div>
        <div class="sub">Category totals in selected period</div>
      </div>
    </div>
    <div class="dd-chart-body" style="padding:0;">
      <div id="categoryTableWrap">
        <table class="dd-summary-table">
          <thead>
            <tr>
              <th>Category</th>
              <th>Items Sold</th>
              <th>Revenue</th>
              <th>% of Total</th>
            </tr>
          </thead>
          <tbody id="categoryTableBody">
            <tr><td colspan="4" style="text-align:center;color:var(--text-muted);padding:20px;">
              Loading…
            </td></tr>
          </tbody>
        </table>
      </div>
    </div>
  </div>

</div>
{% endblock %}

{% block extra_js %}
<script src="{{ url_for('static', filename='js/reports.js') }}"></script>
{% endblock %}

document.addEventListener('DOMContentLoaded', () => {
    const startInput   = document.getElementById('startDate');
    const endInput     = document.getElementById('endDate');
    const applyBtn     = document.getElementById('applyRange');
    const presetBtns   = document.querySelectorAll('.dd-preset-btn');
    const statTotal    = document.getElementById('statTotal');
    const statCount    = document.getElementById('statCount');
    const statAvg      = document.getElementById('statAvg');
    const catBody      = document.getElementById('categoryTableBody');
    const dailySub     = document.getElementById('dailyChartSub');

    let dailyChart   = null;
    let topChart     = null;

    const CHART_COLORS = [
        '#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6',
        '#06b6d4', '#f97316', '#ec4899', '#14b8a6', '#a3e635',
    ];

    // ── Date helpers ──────────────────────────────────────────────

    function toISO(d) {
        return d.toISOString().slice(0, 10);
    }

    function setPreset(days) {
        const end   = new Date();
        const start = new Date();
        start.setDate(start.getDate() - (days - 1));
        startInput.value = toISO(start);
        endInput.value   = toISO(end);
    }

    function activePreset(days) {
        presetBtns.forEach(b => b.classList.toggle('active', parseInt(b.dataset.days) === days));
    }

    // ── Init with 30-day default ──────────────────────────────────

    setPreset(30);
    activePreset(30);

    // ── Fetch & render ────────────────────────────────────────────

    function load() {
        const start = startInput.value;
        const end   = endInput.value;
        if (!start || !end) return;

        dailySub.textContent = `${start} to ${end}`;

        fetch(`/api/reports?start=${start}&end=${end}`)
            .then(r => {
                if (!r.ok) throw new Error('Failed to load');
                return r.json();
            })
            .then(data => {
                renderStats(data);
                renderDailyChart(data.daily);
                renderTopChart(data.top_items);
                renderCategoryTable(data.by_category, data.total_revenue);
            })
            .catch(err => {
                console.error(err);
                catBody.innerHTML = `<tr><td colspan="4" style="text-align:center;color:var(--danger);padding:20px;">
                    <i class="fas fa-circle-exclamation"></i> Failed to load report data.</td></tr>`;
            });
    }

    // ── Summary stats ─────────────────────────────────────────────

    function renderStats(data) {
        statTotal.textContent = '₱' + parseFloat(data.total_revenue || 0).toFixed(2);
        statCount.textContent = data.transaction_count || 0;
        const avg = data.transaction_count
            ? (data.total_revenue / data.transaction_count)
            : 0;
        statAvg.textContent = '₱' + avg.toFixed(2);
    }

    // ── Daily revenue line chart ──────────────────────────────────

    function renderDailyChart(daily) {
        const labels = daily.map(d => d.date);
        const values = daily.map(d => d.revenue);

        if (dailyChart) { dailyChart.destroy(); }

        const ctx = document.getElementById('dailyRevenueChart').getContext('2d');
        dailyChart = new Chart(ctx, {
            type: 'line',
            data: {
                labels,
                datasets: [{
                    label: 'Revenue (₱)',
                    data: values,
                    borderColor: '#2563eb',
                    backgroundColor: 'rgba(37,99,235,0.08)',
                    borderWidth: 2.5,
                    pointBackgroundColor: '#2563eb',
                    pointRadius: labels.length > 60 ? 0 : 3,
                    fill: true,
                    tension: 0.35,
                }]
            },
            options: {
                responsive: true,
                interaction: { mode: 'index', intersect: false },
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        callbacks: {
                            label: ctx => ' ₱' + ctx.parsed.y.toFixed(2)
                        }
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        ticks: {
                            callback: v => '₱' + v.toLocaleString(),
                            font: { size: 11 },
                        },
                        grid: { color: 'rgba(0,0,0,0.05)' },
                    },
                    x: {
                        ticks: {
                            font: { size: 10 },
                            maxTicksLimit: 15,
                            maxRotation: 45,
                        },
                        grid: { display: false },
                    }
                }
            }
        });
    }

    // ── Top items horizontal bar chart ────────────────────────────

    function renderTopChart(items) {
        const labels = items.map(i => i.name);
        const values = items.map(i => i.revenue);
        const colors = items.map((_, idx) => CHART_COLORS[idx % CHART_COLORS.length]);

        if (topChart) { topChart.destroy(); }

        const ctx = document.getElementById('topItemsChart').getContext('2d');
        topChart = new Chart(ctx, {
            type: 'bar',
            data: {
                labels,
                datasets: [{
                    label: 'Revenue (₱)',
                    data: values,
                    backgroundColor: colors,
                    borderRadius: 6,
                    borderSkipped: false,
                }]
            },
            options: {
                indexAxis: 'y',
                responsive: true,
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        callbacks: {
                            label: ctx => ' ₱' + ctx.parsed.x.toFixed(2)
                        }
                    }
                },
                scales: {
                    x: {
                        beginAtZero: true,
                        ticks: {
                            callback: v => '₱' + v.toLocaleString(),
                            font: { size: 11 },
                        },
                        grid: { color: 'rgba(0,0,0,0.05)' },
                    },
                    y: {
                        ticks: { font: { size: 11 } },
                        grid: { display: false },
                    }
                }
            }
        });
    }

    // ── Category table ────────────────────────────────────────────

    function renderCategoryTable(categories, grandTotal) {
        catBody.innerHTML = '';
        if (!categories || !categories.length) {
            catBody.innerHTML = `<tr><td colspan="4" style="text-align:center;color:var(--text-muted);padding:20px;">
                No data in selected period.</td></tr>`;
            return;
        }
        categories.forEach(cat => {
            const pct = grandTotal > 0 ? (cat.revenue / grandTotal * 100).toFixed(1) : '0.0';
